changeSet.sql:
-- PostgreSQL при RENAME автоматически обновляет FK-ссылки (привязаны к OID, не к имени)
ALTER TABLE users RENAME TO auth_users;

-- BCrypt-хеш пароля "changeme" — существующие пользователи должны сменить пароль
ALTER TABLE auth_users ADD COLUMN password_hash TEXT NOT NULL
    DEFAULT '$2a$10$rS.FGqSLhFg5dQGqammYPOBMdAzGR3cdSxYrKPMOgq5YCXQFNMPGG';
ALTER TABLE auth_users ALTER COLUMN password_hash DROP DEFAULT;

ALTER TABLE auth_users ADD COLUMN role TEXT NOT NULL DEFAULT 'USER';

CREATE TABLE token_blacklist (
    jti        TEXT        PRIMARY KEY,
    expires_at TIMESTAMPTZ NOT NULL
);
CREATE INDEX ix_blacklist_expires ON token_blacklist(expires_at);
